#!/bin/bash
# MoAI Harness Observer Hook Wrapper - Generated by moai-adk
# PostToolUse 이벤트를 moai hook harness-observe 커맨드로 전달한다.
# SPEC-V3R3-HARNESS-LEARNING-001 T-P1-03
# 대상 툴: Bash, Edit, Write, Agent, AskUserQuestion

# stdin을 임시 파일에 저장
temp_file=$(mktemp)
trap 'rm -f "$temp_file"' EXIT

cat > "$temp_file"

# moai 커맨드 PATH에서 탐색
if command -v moai &> /dev/null; then
	exec moai hook harness-observe < "$temp_file" 2>/dev/null
fi

# 초기화 시 감지된 Go bin 경로
if [ -f "/Users/goos/go/bin/moai" ]; then
	exec "/Users/goos/go/bin/moai" hook harness-observe < "$temp_file" 2>/dev/null
fi

# 기본 ~/go/bin/moai 경로
if [ -f "$HOME/go/bin/moai" ]; then
	exec "$HOME/go/bin/moai" hook harness-observe < "$temp_file" 2>/dev/null
fi

# 미발견 - 조용히 종료 (Claude Code는 누락된 훅을 정상 처리한다)
exit 0
